// ── WISHLIST TOGGLE ──
async function toggleWishlistStatus() {
  const idx = S.currentModalIdx;
  const b = S.books[idx];
  if (!b) return;
  const isWishlist = b.sold === 'Wishlist';
  const newStatus = isWishlist ? '' : 'Wishlist';
  if (!b._id) { showToast('Could not update wishlist status', 'error'); return; }
  await _supa.from('books').update({ sold_status: newStatus }).eq('id', b._id);
  b.sold = newStatus;
  const btn = document.getElementById('modalWishlistBtn');
  if (btn) btn.textContent = isWishlist ? '+ Wishlist' : 'In Wishlist ✓';
  renderCatalog();
  showToast(isWishlist ? 'Removed from wishlist' : 'Added to wishlist ✓', 'success');
  closeModal();
}

// ── STAR RATING ──
function renderModalStars(book) {
  const row = document.getElementById('modalStarRow');
  if (!row) return;
  const current = parseInt(book.star) || 0;
  row.innerHTML = [1,2,3,4,5].map(n =>
    `<span class="star${current>=n?' lit':''}" onclick="setStarRating(${n})" title="${n} star${n>1?'s':''}" style="font-size:18px;">★</span>`
  ).join('');
}

async function setStarRating(n) {
  const idx = S.currentModalIdx;
  const b = S.books[idx];
  if (!b) return;
  const newRating = parseInt(b.star) === n ? 0 : n; // tap same star to clear
  b.star = String(newRating);
  renderModalStars(b);
  renderCatalog();
  if (b._id) await _supa.from('books').update({ star_rating: newRating || null }).eq('id', b._id);
}

// ── DUPLICATE DETECTION ──
function checkDuplicate(title) {
  if (!title || !S.books || !S.books.length) return;
  const norm = t => t.toLowerCase().replace(/[^a-z0-9]/g,' ').replace(/\s+/g,' ').trim();
  const normTitle = norm(title);
  const match = S.books.find(b => norm(b.title) === normTitle);
  if (match) {
    const banner = document.getElementById('duplicateBanner');
    if (banner) {
      banner.textContent = '⚠ "' + match.title + '" may already be in your library (' + match.condition + ')';
      banner.style.display = 'block';
    } else {
      showToast('⚠ Possible duplicate: "' + match.title + '" is already in your library', 'error', 6000);
    }
  } else {
    const banner = document.getElementById('duplicateBanner');
    if (banner) banner.style.display = 'none';
  }
}

// ── CSV EXPORT ──
function exportCSV() {
  if (!S.books || !S.books.length) { showToast('No books to export', 'error'); return; }
  const headers = ['Title','Author','Artist/Subject','Edition','Year','Publisher','ISBN','Condition','Market Price','Purchase Price','Notes','Cover URL','Date Added','Condition Flags','Sold Status','Star Rating','Collector Note','Where Acquired','Draft'];
  const rows = S.books.filter(b => !S.showSold || b.sold==='Sold').map(b => [
    b.title, b.author, b.artist||'', b.edition||'', b.year||'', b.publisher||'', b.isbn||'',
    b.condition||'', b.price||'', b.cost||'', b.notes||'', b.coverUrl||'', b.dateAdded||'',
    b.flags||'', b.sold||'', b.star||'', b.collectorNote||'', b.location||'', b.draft||''
  ].map(v => '"' + String(v).replace(/"/g,'""') + '"').join(','));
  const csv = [headers.join(','), ...rows].join('\n');
  const blob = new Blob([csv], {type:'text/csv'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'MagiLib-export-' + new Date().toISOString().slice(0,10) + '.csv';
  a.click();
  showToast('CSV exported ✓', 'success', 2000);
}

// ── QUICK ADD FROM BATCH QUEUE ──
async function quickAddFromQueue() {
  if (!photoQueue.length) { showToast('Queue is empty', 'info'); return; }
  const btn = document.getElementById('quickAddBtn');
  const total = photoQueue.length;
  let done = 0;
  let failed = 0;

  if (btn) { btn.disabled = true; }

  // Process every photo in the queue sequentially
  while (photoQueue.length > 0) {
    const item = photoQueue.shift();
    updateQueueUI();
    done++;

    if (btn) btn.innerHTML = '<span class="spinner"></span> ' + done + ' / ' + total + '…';

    try {
      const compressed  = await compressImage(item.dataUrl, 300, 0.6);
      const scanDataUrl = await compressImage(item.dataUrl, 800, 0.85);
      const b64  = scanDataUrl.split(',')[1];
      const mime = (scanDataUrl.match(/data:([^;]+);/) || [,'image/jpeg'])[1];

      const data = await callClaude([{role:'user', content:[
        {type:'image', source:{type:'base64', media_type:mime, data:b64}},
        {type:'text', text:'Extract the book title and author from this cover. Reply ONLY with valid JSON: {"title":"","author":""}'}
      ]}], 150);

      const parsed = JSON.parse(data.content[0].text.replace(/```json|```/g,'').trim());
      const title  = toTitleCase((parsed.title||'').trim()) || 'Unknown Title';
      const author = toTitleCase((parsed.author||'').trim()) || '';

      const draftRow = {
        user_id: _supaUser.id, title, author, artist_subject:'', edition:'', year:'',
        publisher:'', isbn:'', condition:'', market_price:null, purchase_price:null,
        notes:'', cover_url:compressed, date_added:new Date().toISOString().slice(0,10),
        condition_flags:'', sold_status:'', star_rating:null, collectors_note:'',
        where_acquired:'', draft_status:'Draft'
      };
      const { data: inserted } = await _supa.from('books').insert(draftRow).select().single();
      S.books.unshift({
        _id: inserted ? inserted.id : null,
        title, author, artist:'', edition:'', year:'', publisher:'', isbn:'',
        condition:'', price:'', cost:'', notes:'', coverUrl:compressed, rawCover:compressed,
        dateAdded:new Date().toISOString().slice(0,10), flags:'', sold:'', star:'',
        collectorNote:'', location:'', draft:'Draft'
      });

    } catch(e) {
      failed++;
      console.warn('Quick add failed for item ' + done + ':', e.message);
    }
  }

  // All done — re-render once at the end
  renderCatalog();

  if (btn) { btn.disabled = false; btn.textContent = '⚡ Quick Add All'; }

  const added = total - failed;
  if (failed === 0) {
    showToast('✓ ' + added + ' draft' + (added !== 1 ? 's' : '') + ' added', 'success', 3500);
  } else {
    showToast(added + ' added, ' + failed + ' failed — check queue', 'info', 4000);
  }
}

