// ── PRICE REFRESH ──

// Shared lookup: returns {recommended, sources[]} or null
function localPriceLookup(title) {
  if (typeof MARKET_DB === 'undefined') return null;
  const currency = S.settings.currency || 'AUD';
  const sym = currSym();
  const USD_AUD = 1.55, GBP_AUD = 2.02;
  const toAUD = (p, cur) => Math.round(p * (cur === 'GBP' ? GBP_AUD : USD_AUD));

  const normKey = s => {
    let k = s.replace(/[^\x00-\x7F]/g,' ')
             .replace(/\([^)]*\)/g,' ')
             .replace(/\s+-\s+.*$/,'')
             .replace(/\s+by\s+.*$/i,'')
             .toLowerCase()
             .replace(/[^a-z0-9\s]/g,' ')
             .replace(/\s+/g,' ').trim()
             .replace(/^(the|a|an)\s+/,'');
    return k;
  };

  const key = normKey(title);
  const sources = [];
  const priceEntry = lookupPriceDB(title);
  if (priceEntry) {
    const marketAUD = Math.round(toAUD(priceEntry.msrp,'USD') * 0.80);
    sources.push({ name: "Murphy's Magic (In Print)", price: marketAUD, detail: 'Retail USD $' + priceEntry.msrp + ' × 0.80' });
  }
  if (MARKET_DB.qtte[key]) {
    const e = MARKET_DB.qtte[key];
    sources.push({ name: 'QTTE', price: toAUD(e.price,'USD'), detail: 'Listed USD $' + e.price, url: e.url });
  }
  const cmbEntries = MARKET_DB.cmb[key] || [];
  cmbEntries.forEach(e => sources.push({ name: 'Collecting Magic Books', price: toAUD(e.price,'GBP'), detail: 'GBP £' + e.price, url: e.url }));
  const ebayEntries = MARKET_DB.ebay[key] || [];
  if (ebayEntries.length > 0) {
    const avg = ebayEntries.reduce((s,e)=>s+e.price,0)/ebayEntries.length;
    sources.push({ name: 'eBay Sold', price: toAUD(avg,'USD'), detail: ebayEntries.length + ' sold, avg USD $' + avg.toFixed(0) });
  }
  if (MARKET_DB.mc[key]) {
    const e = MARKET_DB.mc[key];
    sources.push({ name: 'Magic Collectibles', price: toAUD(e.price,'USD'), detail: 'Listed USD $' + e.price, url: e.url });
  }
  if (sources.length === 0) return null;
  const prices = sources.map(s=>s.price).sort((a,b)=>a-b);
  const recommended = sources.some(s=>s.name.includes("Murphy"))
    ? sources.find(s=>s.name.includes("Murphy")).price
    : prices[Math.floor(prices.length/2)];
  return { recommended, sources };
}

// ── BULK REFRESH ──
let _bulkQueue = [];
let _bulkIdx = 0;
let _bulkUpdated = 0;
let _bulkSkipped = 0;
let _bulkPending = null; // {idx, newPrice}

function startBulkPriceRefresh() {
  const unsold = S.books
    .map((b,i) => ({b,i}))
    .filter(({b}) => b.sold !== 'Sold' && b.draft !== 'Draft' && b.title);
  if (unsold.length === 0) { showToast('No unsold books found','error'); return; }
  _bulkQueue = unsold;
  _bulkIdx = 0;
  _bulkUpdated = 0;
  _bulkSkipped = 0;
  _bulkPending = null;
  document.getElementById('bulkPriceStatus').style.display = 'none';
  processBulkNext();
}

function processBulkNext() {
  // Skip books with no price result or within 10%
  while (_bulkIdx < _bulkQueue.length) {
    const {b, i} = _bulkQueue[_bulkIdx];
    const result = localPriceLookup(b.title);
    if (!result) { _bulkIdx++; _bulkSkipped++; continue; }
    const newPrice = result.recommended;
    const existingPrice = parseFloat(b.price) || 0;
    // Auto-skip if within 10%
    if (existingPrice > 0 && Math.abs(newPrice - existingPrice) / existingPrice <= 0.10) {
      _bulkIdx++; _bulkSkipped++; continue;
    }
    // Show review card
    _bulkPending = { bookIdx: i, newPrice };
    showPriceReviewCard(b, result, _bulkIdx, _bulkQueue.length);
    return;
  }
  // Done
  closePriceReviewOverlay();
  const msg = _bulkUpdated + ' price' + (_bulkUpdated!==1?'s':'') + ' updated, ' + _bulkSkipped + ' skipped.';
  document.getElementById('bulkPriceStatus').textContent = '✓ Done — ' + msg;
  document.getElementById('bulkPriceStatus').style.display = 'block';
  showToast('Price refresh complete — ' + msg, 'success', 4000);
}

function showPriceReviewCard(b, result, idx, total) {
  const sym = currSym();
  const currency = S.settings.currency || 'AUD';

  // Counter + title + author
  document.getElementById('priceReviewCounter').textContent = (idx+1) + ' of ' + total + ' books';
  document.getElementById('priceReviewTitle').textContent = b.title || 'Untitled';
  document.getElementById('priceReviewAuthor').textContent = b.author || '';

  // Cover thumbnail
  const coverWrap = document.getElementById('priceReviewCoverWrap');
  const coverUrl = b.rawCover || b.coverUrl || '';
  if (coverUrl) {
    const _img = document.createElement('img'); _img.src = coverUrl; _img.style.cssText = 'width:100%;height:100%;object-fit:cover;'; _img.onerror = function(){ coverWrap.innerHTML='\U0001f4d6'; coverWrap.style.opacity='0.3'; }; coverWrap.innerHTML=''; coverWrap.appendChild(_img);
    coverWrap.style.opacity = '1';
  } else {
    coverWrap.innerHTML = '📖';
    coverWrap.style.opacity = '0.3';
  }

  // Existing price
  const existing = parseFloat(b.price) || 0;
  document.getElementById('priceReviewOld').textContent = existing > 0 ? 'Current price: ' + sym + existing.toFixed(0) : 'No current price set';

  // Suggested price
  document.getElementById('priceReviewNew').textContent = sym + result.recommended + ' ' + currency;

  // Currency symbol on input
  document.getElementById('priceReviewCurrSym').textContent = sym;

  // Pre-fill custom input with suggested price
  document.getElementById('priceReviewCustom').value = result.recommended.toFixed(2);

  // Sources
  document.getElementById('priceReviewSources').innerHTML = result.sources
    .map(s => (s.url ? '<a href="'+s.url+'" target="_blank" style="color:var(--accent);text-decoration:none;">' : '') +
               s.name + ': ' + sym + s.price + ' (' + s.detail + ')' +
               (s.url ? '</a>' : ''))
    .join('<br>');

  document.getElementById('priceReviewOverlay').style.display = 'flex';
  // Focus the custom input for quick keyboard editing
  setTimeout(() => document.getElementById('priceReviewCustom').select(), 100);
}

function priceReviewApprove() {
  if (!_bulkPending) return;
  const { bookIdx, newPrice } = _bulkPending;
  const b = S.books[bookIdx];
  // Use custom input value if set, otherwise fall back to suggested price
  const customInput = document.getElementById('priceReviewCustom');
  const finalPrice = customInput && parseFloat(customInput.value) > 0
    ? parseFloat(customInput.value)
    : newPrice;
  const oldPrice = b.price;
  b.price = finalPrice.toFixed(2);
  // Write to Supabase
  if (b._id) {
    _supa.from('books').update({ market_price: parseFloat(b.price) }).eq('id', b._id).then(()=>{});
  }
  _bulkUpdated++;
  _bulkPending = null;
  _bulkIdx++;
  processBulkNext();
}

function priceReviewDecline() {
  _bulkSkipped++;
  _bulkPending = null;
  _bulkIdx++;
  processBulkNext();
}

function stopBulkPriceRefresh() {
  closePriceReviewOverlay();
  if (_bulkUpdated > 0 || _bulkSkipped > 0) {
    const msg = _bulkUpdated + ' updated, ' + _bulkSkipped + ' skipped before stopping.';
    document.getElementById('bulkPriceStatus').textContent = msg;
    document.getElementById('bulkPriceStatus').style.display = 'block';
  }
}

function closePriceReviewOverlay() {
  document.getElementById('priceReviewOverlay').style.display = 'none';
  _bulkPending = null;
}

// ── FETCH PRICE IN EDIT MODAL ──
async function fetchPriceForEdit() {
  const title = (document.getElementById('edit-title').value || '').trim();
  const author = (document.getElementById('edit-author').value || '').trim();
  if (!title) { showToast('Title is required', 'error'); return; }

  const btn = document.getElementById('editFetchPriceBtn');
  btn.disabled = true;
  btn.innerHTML = '<span class="spinner"></span> Looking up…';

  const result = localPriceLookup(title);

  if (!result) {
    // Check discontinued list
    const discEntry = (typeof MARKET_DB !== 'undefined' && MARKET_DB.disc) ? MARKET_DB.disc[title.toLowerCase().replace(/[^a-z0-9\s]/g,' ').replace(/\s+/g,' ').trim()] : null;
    const msg = discEntry ? '⚠ Possibly Out of Print — not found in any price database.' : 'Not found in any price database.';
    showToast(msg, 'error', 4000);
    btn.disabled = false;
    btn.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>Fetch Price';
    return;
  }

  const sym = currSym();
  const currency = S.settings.currency || 'AUD';
  const newPrice = result.recommended;
  const sourceText = result.sources.map(s => s.name + ': ' + sym + s.price).join(' · ');

  // Show inline confirmation in the modal
  const confirmed = confirm('Update market price to ' + sym + newPrice + ' ' + currency + '? Sources: ' + sourceText);

  if (confirmed) {
    const priceEl = document.getElementById('edit-price');
    if (priceEl) {
      priceEl.value = newPrice.toFixed(2);
      _markEditDirty();
      showToast('Price updated to ' + sym + newPrice, 'success', 2500);
    }
  }

  btn.disabled = false;
  btn.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>Fetch Price';
}

// ── DRAFT ACTION SHEET ──
let _draftActionIdx = null;

function openDraftActions(idx) {
  _draftActionIdx = idx;
  const b = S.books[idx];
  const titleEl = document.getElementById('draftActionTitle');
  if (titleEl) titleEl.textContent = b.title || 'Untitled Draft';
  document.getElementById('draftActionOverlay').classList.remove('hidden');
}

function closeDraftActions() {
  document.getElementById('draftActionOverlay').classList.add('hidden');
  _draftActionIdx = null;
}

function draftActionEdit() {
  const idx = _draftActionIdx;
  closeDraftActions();
  setTimeout(() => openDraftInAddForm(idx), 120);
}

function draftActionDelete() {
  const idx = _draftActionIdx;
  if (idx === null) return;
  const b = S.books[idx];
  const rowNum = idx + 2;
  closeDraftActions();

  if (b._id) {
    _supa.from('books').delete().eq('id', b._id).then(()=>{});
  }
  S.books.splice(idx, 1);
  renderCatalog();
  showToast('Draft deleted', 'success', 2500);
}

function openDraftInAddForm(idx) {
  const b = S.books[idx];
  if (!b) return;
  // Pre-populate the Add form
  showView('entry');
  setTimeout(() => {
    const fields = [
      {id:'f-title', val:b.title},
      {id:'f-author', val:b.author},
      {id:'f-artist', val:b.artist||''},
    ];
    fields.forEach(f => {
      const el = document.getElementById(f.id);
      if (el && f.val) el.value = f.val;
    });
    // Set cover
    if (b.coverUrl) {
      S.coverUrl = b.coverUrl;
      const img = document.getElementById('coverImg');
      const ph = document.getElementById('coverPlaceholder');
      if (img) { img.src = b.coverUrl; img.style.display='block'; }
      if (ph) ph.style.display='none';
    }
    // Store draft row index for deletion after save
    S.draftRowIdx = idx;
    S.draftRowNum = idx + 2;
    // Update save button to signal draft-completion mode
    const saveBtn = document.getElementById('saveBtn');
    if (saveBtn) { saveBtn.textContent = 'Save and Delete Draft'; saveBtn.style.background = 'var(--gold)'; saveBtn.style.color = '#1A1814'; }
    showToast('Draft loaded — fill in details and save', 'info', 3000);
  }, 200);
}


